const inputMask = iran.mask;      // '### ### ####'
const displayFormat = iran.format; // '000 000 0000'

// Validate a formatted national number
function isValidNumber(country: CountryItem, formatted: string): boolean {
  return new RegExp(country.regex).test(formatted);
}

const valid = isValidNumber(iran, '912 123 4567');

