import { COUNTRIES, CountryItem } from '@acorex/core/constants';

// Find by ISO alpha-2 code
const iran = COUNTRIES.find((c) => c.code === 'ir');

// Filter by region
const europe = COUNTRIES.filter((c) => c.regions.includes('europe'));
const middleEast = COUNTRIES.filter((c) => c.regions.includes('middle-east'));

// Build a map keyed by dialing code
const byDialCode = new Map<string, CountryItem[]>();
for (const country of COUNTRIES) {
  const list = byDialCode.get(country.iso2code) ?? [];
  list.push(country);
  byDialCode.set(country.iso2code, list);
}

// Include / exclude specific countries (pattern used by ax-phone-box)
const included = ['ir', 'us', 'de'];
const allowed = COUNTRIES.filter((c) => included.includes(c.code));

import { COUNTRIES, CountryItem } from '@acorex/core/constants';

function sortCountries(list: CountryItem[]): CountryItem[] {
  return [...list].sort((a, b) => {
    const priorityA = a.orderPriority ?? Number.MAX_SAFE_INTEGER;
    const priorityB = b.orderPriority ?? Number.MAX_SAFE_INTEGER;

    if (priorityA !== priorityB) {
      return priorityA - priorityB;
    }

    return a.name.localeCompare(b.name);
  });
}

const sorted = sortCountries(COUNTRIES);

import { COUNTRIES, CountryItem } from '@acorex/core/constants';

interface ParsedPhone {
  country: CountryItem | null;
  countryCode: string | null;
  nationalNumber: string;
}

function parsePhoneNumber(fullNumber: string): ParsedPhone {
  let normalized = fullNumber.replace(/[^0-9+]/g, '');

  if (normalized.startsWith('00')) {
    normalized = '+' + normalized.slice(2);
  }

  // Match longest dialing prefix first (+1268 before +1)
  const sorted = [...COUNTRIES].sort(
    (a, b) => b.iso2code.length - a.iso2code.length,
  );

  for (const country of sorted) {
    if (normalized.startsWith(country.iso2code)) {
      return {
        country,
        countryCode: country.iso2code,
        nationalNumber: normalized.slice(country.iso2code.length),
      };
    }
  }

  return { country: null, countryCode: null, nationalNumber: normalized };
}

// Example
parsePhoneNumber('+989121234567');
// => { country: Iran, countryCode: '+98', nationalNumber: '9121234567' }

import { COUNTRIES, CountryItem } from '@acorex/core/constants';

function isValidNationalNumber(
  country: CountryItem,
  formattedNumber: string,
): boolean {
  if (!country.regex) return true;
  return new RegExp(country.regex).test(formattedNumber);
}

const iran = COUNTRIES.find((c) => c.code === 'ir')!;

isValidNationalNumber(iran, '912 123 4567'); // depends on iran.regex

import { Component } from '@angular/core';
import { NgStyle } from '@angular/common';
import { COUNTRIES, COUNTRIES_FLAG_BASE64, CountryItem } from '@acorex/core/constants';

@Component({
  selector: 'app-country-list',
  imports: [NgStyle],
  template: `
    @for (country of countries; track country.code) {
      <div class="country-item">
        @if (country.bkPosition) {
          <div
            class="country-flag"
            [style.background-image]="'url(' + flagSprite + ')'"
            [style.background-position]="
              country.bkPosition!.x + ' ' + country.bkPosition!.y
            "
          ></div>
        }
        <span>{{ country.name }}</span>
        <span>{{ country.iso2code }}</span>
      </div>
    }
  `,
  styles: `
    .country-flag {
      width: 25px;
      height: 20px;
      background-repeat: no-repeat;
    }
    .country-item {
      display: flex;
      align-items: center;
      gap: 0.5rem;
    }
  `,
})
export class CountryListComponent {
  countries: CountryItem[] = COUNTRIES;
  flagSprite = COUNTRIES_FLAG_BASE64;
}

import { COUNTRIES } from '@acorex/core/constants';

interface SelectOption {
